INSERT INTO xt_spirit_form (name, description, liked_tags, disliked_tags) VALUES
('小狐妖','三百年道行小狐狸。化形后双马尾小女孩——实际年龄比大多数修士都大。喜欢亮晶晶的东西口头禅"道友请留步"——说完通常没好事。','["crystal","ore","rare","flower","jewel"]','["dark","evil","bone","blood","rotten"]'),
('春秋蝉','通体晶莹的蝉据说能穿越季节知天地春秋。实际大部分时间在树上趴着——美其名曰"悟道"。','["wood","herb","nature","pure","earth"]','["metal","fire","forge_base","violent","destruction"]'),
('鲲','北冥有鱼其名为鲲——鲲之大一锅炖不下。上古神兽幼体胃口奇大每天吃自身重量三倍。养鲲的不是穷死的就是被吃穷的。','["ore","metal","fire","meat","fruit","holy"]','["vegetable","flower","balance","small"]'),
('麒麟','瑞兽麒麟幼崽——通体五彩鳞片走路自带祥云。性格温和——但别以为好欺负。上一只对麒麟不敬的妖兽三千年前就被烧成灰了。','["holy","pure","herb","flower","nature","jewel"]','["dark","evil","bone","blood","forbidden"]'),
('貔貅','只进不出招财神兽。财源滚滚——但只招财不理财，把灵石都吞了不吐。所以富得快穷得更快。','["crystal","ore","metal","jewel","rare"]','["wood","herb","flower","organic","common"]'),
('九命猫','猫妖最高形态——九条命九个性格每天随机切换。"昨天还粘着撒娇今天怎么就不理我了？"欢迎来到猫系地灵世界。','["fish","meat","crystal","night","mysterious"]','["dog","loud","common","dirty","sweat"]'),
('白泽','通晓万物的智慧神兽。知道你炼丹失败法宝炸炉为什么踩到妖兽尾巴——但从不说而是一副"这你都不知道"的表情。','["knowledge","rare","holy","crystal","cosmic"]','["violent","destruction","loud","sweat","beast"]'),
('小青龙','年幼青龙——幼年特别可爱成年特别可怕。喜欢盘成团睡觉睡醒喷龙息——每次刚好喷主人脸上。','["dragon","scale","fire","wind","thunder"]','["dark","rotten","undead","artificial","fake"]'),
('玄龟','活了不知多少万年的老乌龟——仙帝坐骑仙帝陨落后流浪。说话极慢一个"好"字十分钟。养它的修士必须有耐心。','["water","ice","earth","herb","pure","calm"]','["fire","loud","fast","violent","impatient"]'),
('混沌精灵','诞生于混沌中无固定形态——时而如雾时而如水时而像没脸小猫。没人知道它到底是什么但有确定事实：会偷灵石。','["chaos","void","unknown","mysterious","rare"]','["order","system","common","structured","balance"]'),
('书灵','蝌蚪大小灵体最爱趴在玉简上"阅读"——没人确定能不能读懂。引经据典一半自己编。最喜欢炼丹时飘丹炉上被炸飞——下次还来。','["knowledge","crystal","pure","jewel","rare","cosmic"]','["violent","loud","blood","bone","rotten","forbidden"]'),
('月兔','住在月亮上的兔子——的凡间表亲。自称本体在天上捣药真身只在此休息。号称擅长种灵植——实际种什么死什么唯一例外是灵茶树苗。','["herb","flower","seed","nature","wood","moon"]','["fire","dark","violence","bone","sweat","rotten"]'),
('酒虫','嗜酒如命的灵虫。无酒环境活不下去——福地必须常备灵酒。平时跟米粒一样大——灌满酒可单挑金丹期妖兽（有目击者）。','["ore","metal","forge_base","crystal","rare","wine"]','["vegetable","herb","pure","calm","structured","small"]'),
('雷灵','一团跳跃雷球从不安分——跳屋顶跳树梢跳主人脸上。最爱雷系法决——有雷法地方一定有它兴奋得浑身冒电火花。养它的修士每三个月换一件道袍——被电焦的。','["lightning","thunder","storm","sky","speed","power"]','["water","ice","calm","slow","earth","wood"]'),
('丹精','巴掌大小人头顶迷你丹炉到处跑。唯一爱好炼丹——指甲盖大丹炉炼出丹同样小到肉眼看不见。据说是炼丹大能陨落后执念所化。','["fire","herb","pill","alchemy","rare","pure"]','["dark","evil","bone","blood","violent","loud"]'),
('夕兽','年兽远亲除夕夜从福地冒出来吓其他灵兽——太小跟松鼠差不多每次被无视——委屈钻回地底等下个除夕。给整个福地施加微弱幸运BUFF——微弱到感觉不到但养了觉得运气好。','["festival","holy","pure","rare","mysterious","jewel"]','["dark","evil","bone","blood","forbidden","loud"]'),
('笔仙','一支会自己飞着写字的毛笔灵体。认得所有文字包括失传上古篆文——写字极慢每天十个字——喜欢在不该写的地方写：丹方空白处法器表面道袍背面。某修士玄铁甲背被写整篇《逍遥游》后自称"逍遥甲士"——实则洗不掉。','["knowledge","pure","rare","crystal","holy","cosmic"]','["fire","dark","evil","blood","rotten","loud"]'),
('风铃精','风铃化成的灵体。微风时悦耳铃声——大风时吵醒整座福地。经常挂修士衣服上出门旅游到了新地方就叮当响。秘境潜行时突然响——已导致无数次走火入魔。','["wind","sound","rare","crystal","pure","nature"]','["stealth","dark","silence","blood","metal","forge_base"]'),
('小火灵','火元素灵体最常见的一种——比打火机稍大一撮。火灵根时更活跃更大更亮——水灵根时整天蔫甚至会熄灭。段子:"换水灵根马甲回家小火灵不见了——床底留信：主人我走了谢谢你但我再也不想看到水了。"','["fire","crystal","rare","ore","metal","power"]','["water","ice","calm","herb","wood","rotten"]'),
('虚空触须','从虚空裂缝伸出的一条——触须？没固定形状。偶尔从虚空探出把福地东西抓走又放回——有时东西换了位置有时多了奇怪东西有时少了什么。"有虚空触须的福地你永远不知道明天醒来看到什么。"混沌爱好者终极地灵。','["void","chaos","unknown","mysterious","legendary","cosmic"]','["order","system","structured","balance","common","pure"]');
